import {
  ApplicationConfig,
  provideBrowserGlobalErrorListeners,
  provideZoneChangeDetection,
} from '@angular/core';
import { provideRouter } from '@angular/router';
import { provideHttpClient } from '@angular/common/http';
import { routes } from './app.routes';

export const appConfig: ApplicationConfig = {
  providers: [
    provideBrowserGlobalErrorListeners(),
    provideZoneChangeDetection({ eventCoalescing: true }),
    provideRouter(routes),
    provideHttpClient(),
  ],
};

@if (product()) {
  <div class="max-w-md mx-auto mt-8 bg-white rounded-xl shadow-lg overflow-hidden">
    <img
      [src]="product()!.image"
      [alt]="product()!.name"
      class="w-full h-64 object-cover"
    />
    <div class="p-6">
      <h1 class="text-2xl font-bold text-gray-900 mb-3">
        {{ product()!.name }}
      </h1>
      <p class="text-gray-600 text-sm mb-4 leading-relaxed">
        {{ product()!.description }}
      </p>
      <p class="text-2xl font-bold text-green-600">
        {{ product()!.price | currency }}
      </p>
    </div>
  </div>
}

import { Component, inject } from '@angular/core';
import { toSignal } from '@angular/core/rxjs-interop';
import { CurrencyPipe } from '@angular/common';
import { ProductService } from './services/product.service';

@Component({
  selector: 'app-root',
  templateUrl: './app.html',
  styleUrl: './app.css',
  imports: [CurrencyPipe],
})
export class App {
  private readonly productService = inject(ProductService);
  protected readonly product = toSignal(this.productService.getProduct());
}

export interface Product {
  id: number;
  name: string;
  description: string;
  price: number;
  image: string;
}

import { inject, Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Product } from '../models/product.model';
import { Observable } from 'rxjs';

@Injectable({
  providedIn: 'root',
})
export class ProductService {
  private readonly http = inject(HttpClient);
  private readonly apiUrl =
    'https://storage.googleapis.com/lowgular-platform/mocks/product.json';

  getProduct(): Observable<Product> {
    return this.http.get<Product>(this.apiUrl);
  }
}

